 1	import React, { FC } from 'react';
 2	
 3	import { Button, ButtonVariant, Card, CardBody, CardTitle } from '@patternfly/react-core';
 4	import { useNetworkingTranslation } from '@utils/hooks/useNetworkingTranslation';
 5	import { NetworkPolicyRule } from '@utils/models';
 6	
 7	import NetworkPolicyAddPeerDropdown from '../../NetworkPolicyAddPeerDropDown';
 8	import { NetworkPolicyEgressIngress, NetworkPolicyPeerType } from '../../utils/types';
 9	import { emptyPeer } from '../../utils/utils';
10	import NetworkPolicyPorts from '../NetworkPolicyFormPorts';
11	
12	import NetworkPolicyRuleConfigPanelRulePeer from './components/NetworkPolicyRuleConfigPanelRulePeer';
13	import { getPeersHelpText } from './utils/utils';
14	
15	type NetworkPolicyRuleConfigPanelProps = {
16	  direction: NetworkPolicyEgressIngress;
17	  onChange: (rule: NetworkPolicyRule) => void;
18	  onRemove: () => void;
19	  policyNamespace: string;
20	  rule: NetworkPolicyRule;
21	};
22	
23	const NetworkPolicyRuleConfigPanel: FC<NetworkPolicyRuleConfigPanelProps> = ({
24	  direction,
25	  onChange,
26	  onRemove,
27	  policyNamespace,
28	  rule,
29	}) => {
30	  const { t } = useNetworkingTranslation();
31	
32	  const addPeer = (type: NetworkPolicyPeerType) => {
33	    rule.peers = [emptyPeer(type), ...rule.peers];
34	    onChange(rule);
35	  };
36	  const isIngress = direction === NetworkPolicyEgressIngress.ingress;
37	  return (
38	    <Card>
39	      <CardTitle component="h4">
40	        <label>{isIngress ? t('Ingress rule') : t('Egress rule')}</label>
41	        <Button
42	          data-test={`remove-${direction}-rule`}
43	          onClick={onRemove}
44	          variant={ButtonVariant.link}
45	        >
46	          {t('Remove')}
47	        </Button>
48	        <NetworkPolicyAddPeerDropdown
49	          onSelect={addPeer}
50	          title={isIngress ? t('Add allowed source') : t('Add allowed destination')}
51	        />
52	      </CardTitle>
53	      <CardBody>
54	        <div className="help-block" id="ingress-peers-help">
55	          <p>{getPeersHelpText(direction)}</p>
56	        </div>
57	      </CardBody>
58	      <CardBody>
59	        {rule.peers.map((peer, index) => (
60	          <NetworkPolicyRuleConfigPanelRulePeer
61	            direction={direction}
62	            index={index}
63	            key={peer.key}
64	            onChange={onChange}
65	            peer={peer}
66	            policyNamespace={policyNamespace}
67	            rule={rule}
68	          />
69	        ))}
70	        <NetworkPolicyPorts
71	          onChange={(ports) => {
72	            rule.ports = ports;
73	            onChange(rule);
74	          }}
75	          ports={rule.ports}
76	        />
77	      </CardBody>
78	    </Card>
79	  );
80	};
81	
82	export default NetworkPolicyRuleConfigPanel;

